node -e "const fs=require('fs'),path=require('path'),os=require('os'); const tmp=fs.mkdtempSync(path.join(os.tmpdir(),'doc-')); fs.mkdirSync(path.join(tmp,'.ai-artifacts'),{recursive:true}); fs.writeFileSync(path.join(tmp,'package.json'),'{}'); fs.writeFileSync(path.join(tmp,'.ai-artifacts/artifacts.yml'),'version: 1
packages: {}
artifacts: []'); fs.writeFileSync(path.join(tmp,'.ai-artifacts/lock.yml'),'packages: {}
artifacts: {}'); fs.writeFileSync(path.join(tmp,'AGENTS.md'),''); const {doctorAIArtifacts}=require('./packages/ai-artifacts/doctor.js'); const result=doctorAIArtifacts(tmp,{packageRoot:path.resolve('packages/ai-artifacts')}); const msgs=result.checks.map(c=>c.message); if(!msgs.some(m=>m.includes('audit trail'))) process.exit(1)"

